// Build Rows (per item)
// 아이템 1개 = 시트 1행 생성. "할인가격"은 total/qty를 1순위로 사용.

function cleanName(s) {
  return String(s ?? '').replace(/\s*-\s*온유어마크 온라인 스토어$/,'').trim();
}
function toNum(v, fallback = 0) {
  const n = Number(String(v ?? '').replace(/[^\d.-]/g, ''));
  return Number.isFinite(n) ? n : fallback;
}
function pick(obj, keys) {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== '') return String(v);
  }
  return '';
}

// ✅ $input.first() 대신 $json을 기준으로 (실행 모드에 덜 민감)
const data = $json || {};
const groups = Array.isArray(data.groups) ? data.groups : [];

// 1) 아이템 배열 추정
function guessItems(d, gs) {
  for (const g of gs) if (Array.isArray(g?.items) && g.items.length) return g.items;
  if (Array.isArray(d.items) && d.items.length) return d.items;
  return [];
}

// 2) 주문자 정보 추정 (groups[0] 최우선)
function guessBuyer(d, gs) {
  const g0 = gs[0] || {};
  const fromG0 = { name: g0.name, crew_name: g0.crew_name, vendor: g0.vendor, campaign: g0.campaign, phone: g0.phone, email: g0.email, address: g0.address, memo: g0.memo, marketing_consent: g0.marketing_consent };
  if (Object.values(fromG0).some(v => (v ?? '') !== '')) return fromG0;

  const found = d || {};
  return {
    name:    pick(found, ['name','buyer_name','customer_name','이름']),
    phone:   pick(found, ['phone','tel','mobile','전화','전화번호']),
    email:   pick(found, ['email','mail','이메일','buyer_email']),
    address: pick(found, ['address','addr','주소','buyer_address']),
    memo:    pick(found, ['memo','note','요청사항','buyer_memo']),
  };
}

const items = guessItems(data, groups);
const buyer = guessBuyer(data, groups);

// ✅ [추가] 한국 시간 및 동의 여부 판별
const now = new Date();
const krTime = new Date(now.getTime() + (9 * 60 * 60 * 1000)).toISOString().replace('T', ' ').substring(0, 19);
const isConsent = buyer.marketing_consent === true;

const shippingTotal = toNum(data.summary?.shipping_total);
const grandTotal    = toNum(data.summary?.grand_total);

// ✅ 아이템이 비어 있으면 다음 노드가 안 도니, 여기서 바로 빈 배열 반환(원인 파악용)
if (!items.length) {
  // 원인 확인을 위해, 최소한 1개 아이템을 만들고 싶으면 아래 return을 주석 처리하고 임시행을 넣으셔도 됩니다.
  return [];
}

const rows = items.map((it, idx) => {
  const qty  = Math.max(1, toNum(it.qty ?? it.quantity, 1));

  const totalNum       = toNum(it.total, 0);
  const unitDiscounted = totalNum > 0 ? Math.round(totalNum / qty) : toNum(it.price, 0);

  const hasOriginal = it.original_price != null && String(it.original_price).trim() !== '';
  const hasListed   = it.listed_price   != null && String(it.listed_price).trim()   !== '';
  const consumer    = hasOriginal ? toNum(it.original_price, 0)
                   : hasListed  ? toNum(it.listed_price, 0)
                   : '';

  let discountCell = '0';
  if (it.discount_mode === 'fixed') discountCell = '고정';
  else if (it.discount_rate != null && String(it.discount_rate).trim() !== '') discountCell = String(Number(it.discount_rate));

  const size = it.size ?? it.options?.size ?? it.option?.size ?? it.variant ?? it.selectedSize ?? '';

  const itemTotal = totalNum > 0 ? totalNum : unitDiscounted * qty;

  const isLast = (idx === items.length - 1);
  const orderShippingCell = isLast ? shippingTotal : '';
  const orderGrandCell    = isLast ? grandTotal    : '';

  const noteCell = String(it.notes ?? '').trim();

  return {
    '소속'         : buyer.crew_name || '일반',
    '벤더'         : buyer.vendor || '영산',
    '캠페인'       : buyer.campaign || '',
    '이름'           : buyer.name || '',
    '전화번호'       : buyer.phone || '',
    '주소'           : buyer.address || '',
    '이메일'         : buyer.email || '',
    '상품명'         : cleanName(it.name),
    '사이즈'         : String(size || ''), 
    '수량'           : qty,
    '소비자가격'     : consumer,
    '할인율'         : discountCell,
    '할인가격'       : unitDiscounted,
    '상품총가격'     : itemTotal,

    // ✅ 영산 공급가 마진 계산용 3형제 추가!
    '공급할인율'     : it.supply_rate ? (it.supply_rate + '%') : '',
    '공급단가'       : it.supply_price || '',
    '공급총가격'     : it.supply_total || '',

    '총배송비'       : orderShippingCell,
    '총가격'         : orderGrandCell,
    '참고사항(고객)' : noteCell,
    '마케팅 수신 동의': isConsent ? 'TRUE' : 'FALSE',
    '동의 일시'      : isConsent ? krTime : '',
    '주문상태'       : '입금대기',
    '운송장번호'     : '',
    '안내사항(관리자)': ''
  };
});

return rows.map(r => ({ json: r }));

/**
 * Compose Order Summary — Run Once for Each Item
 * 입력: Finalize Response의 단일 아이템
 * 출력:
 *  - email_subject / email_html : 고객 확인용 메일 콘텐츠
 *  - buyer_*                    : 수신자 정보
 *  - has_buyer_email            : IF 노드용 "진짜" 불린
 *  - webhook_payload            : 사내(인커밍 웹훅) 전송용 순수 객체
 */

const data  = $json || {};
const group = (data.groups && data.groups[0]) || {};
const items = Array.isArray(group.items) ? group.items : [];

// 안전 변환 유틸
const toNum = (v, d = 0) => {
  const n = Number(String(v ?? '').replace(/[^\d.-]/g, ''));
  return Number.isFinite(n) ? n : d;
};
const toStr = (v) => String(v ?? '');

// 주문자
const buyer = {
  name:    toStr(group.name),
  phone:   toStr(group.phone),
  email:   toStr(group.email),
  address: toStr(group.address),
  memo:    toStr(group.memo),
};

// 표기용 화폐
const money = (n) => Number(toNum(n, 0)).toLocaleString('ko-KR') + '원';

// 이메일/웹훅용 라인 가공
const rows = items.map((it, i) => {
  const discountLabel =
    (it.discount_mode === 'fixed') ? '고정'
    : (toNum(it.discount_rate, 0) > 0 ? `${toNum(it.discount_rate, 0)}%` : '0%');

  // 표시 가격: 소비자가(정가) → 표시가(listed) → price
  const displayPrice =
    (it.display_price != null ? it.display_price
      : (it.original_price ?? it.listed_price ?? it.price));

  return {
    idx:            i + 1,                 // 이메일엔 표시 안함(시트용)
    name:           toStr(it.name),
    url:            toStr(it.product_url),
    display_price:  toNum(displayPrice, 0),
    discount_label: discountLabel,
    qty:            toNum(it.qty, 1),
    total:          toNum(it.total, 0),
    size:           toStr(it.size),
    notes:          toStr(it.notes),
  };
});

const itemsTotal    = toNum(data.summary?.items_total, 0);
const shippingTotal = toNum(data.summary?.shipping_total, 0);
const grandTotal    = toNum(data.summary?.grand_total, 0);

// 테이블 Row HTML
const rowHtml = rows.map(r => `
  <tr>
    <td class="left cell name">
      <div style="font-weight:600">${r.name || '(상품명 미확인)'}</div>
      <div class="sub">
        <a href="${r.url}" target="_blank" rel="noreferrer" class="link">상품 페이지 열기</a>
        ${r.size ? ` · 사이즈: ${r.size}` : ''}${r.notes ? ` · 메모: ${r.notes}` : ''}
      </div>
    </td>
    <td class="num cell">${money(r.display_price)}</td>
    <td class="center cell">${r.discount_label}</td>
    <td class="center cell">${r.qty}</td>
    <td class="num cell">${money(r.total)}</td>
  </tr>
`).join('');

// 이메일 본문 (반응형 스타일 포함)
const emailHtml = `
  <div style="font-family:system-ui,-apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif;color:#0f172a">
    <style>
      /* 기본 테이블/셀 스타일 */
      .tbl{width:100%;border-collapse:collapse;margin-top:8px}
      .tbl th,.tbl td{padding:10px;border-bottom:1px solid #eee;vertical-align:middle}
      .head th{border-bottom:2px solid #e5e7eb}
      .left{ text-align:left } .center{ text-align:center } .num{ text-align:right }
      .sub{ font-size:12px; color:#64748b; margin-top:2px }
      .link{ color:#0a7cff; text-decoration:none }
      .cell{ white-space:nowrap } .name{ white-space:normal }
      /* 열 폭(데스크톱 기준) */
      .w-name{ width:44% } .w-price{ width:14% } .w-disc{ width:12% } .w-qty{ width:10% } .w-sub{ width:20% }
      /* 계좌 안내: 데스크톱/모바일 토글 */
      .acct-d{ display:inline } .acct-m{ display:none; white-space:pre-line }
      /* 모바일 최적화 */
      @media screen and (max-width:600px){
        .tbl, .tbl td, .tbl th{ font-size:16px !important; line-height:1.42 }
        .w-name,.w-price,.w-disc,.w-qty,.w-sub{ width:auto }
        .acct-d{ display:none !important }
        .acct-m{ display:inline !important }
      }
    </style>

    <h2 style="margin:0 0 12px">[공동구매] 주문 접수 확인</h2>
    <p style="margin:0 0 6px">주문자: <b>${buyer.name || '-'}</b></p>
    <p style="margin:0 0 6px">연락처: ${buyer.phone || '-'}</p>
    <p style="margin:0 0 6px">이메일: ${buyer.email || '-'}</p>
    <p style="margin:0 0 12px">주소: ${buyer.address || '-'}</p>

    <table class="tbl" cellpadding="0" cellspacing="0" role="presentation">
      <thead class="head">
        <tr>
          <th class="left w-name">상품명</th>
          <th class="w-price">가격</th>
          <th class="w-disc">할인</th>
          <th class="w-qty">수량</th>
          <th class="w-sub">소계</th>
        </tr>
      </thead>
      <tbody>
        ${rowHtml || `<tr><td colspan="5" class="center" style="padding:12px;color:#64748b">상품 없음</td></tr>`}
      </tbody>
      <tfoot>
        <!-- 라벨 좌측, 금액 우측 -->
        <tr>
          <td colspan="4" class="left" style="padding:10px;border-top:2px solid #e5e7eb">상품 합계</td>
          <td class="num" style="padding:10px;border-top:2px solid #e5e7eb">${money(itemsTotal)}</td>
        </tr>
        <tr>
          <td colspan="4" class="left" style="padding:8px;color:#64748b">배송비</td>
          <td class="num" style="padding:8px;color:#64748b">${money(shippingTotal)}</td>
        </tr>
        <tr>
          <td colspan="4" class="left" style="padding:12px 10px;font-weight:700">총 결제금액</td>
          <td class="num" style="padding:12px 10px;font-weight:700">${money(grandTotal)}</td>
        </tr>
        <!-- 계좌 정보: PC 메일 호환을 위해 인라인 정렬 + align 속성 병행 -->
        <tr>
          <td colspan="4" class="left" style="padding:14px 10px 0;font-weight:700;text-align:left">입금계좌 정보</td>
          <td colspan="1" align="right" style="padding:14px 10px 0;text-align:right;">
            <span class="acct-d" style="display:inline;">신한은행 / 100035090178 (예금주:(주)모라)</span>
            <span class="acct-m" style="display:none;white-space:pre-line;">신한은행
100035090178
(예금주:(주)모라)</span>
          </td>
        </tr>
      </tfoot>
    </table>
  </div>
`;

// 인커밍 웹훅으로 넘길 안전한 객체
const webhook_payload = {
  order_id: new Date().toISOString(),
  buyer_name:    buyer.name,
  buyer_phone:   buyer.phone,
  buyer_email:   buyer.email,
  buyer_address: buyer.address,
  buyer_memo:    buyer.memo,
  summary: {
    items_total: itemsTotal,
    shipping_total: shippingTotal,
    grand_total: grandTotal,
  },
  items: rows, // 시트/사내 시스템용 라인 (idx 포함)
};

return [{
  json: {
    buyer_name:    buyer.name,
    buyer_phone:   buyer.phone,
    buyer_email:   buyer.email,
    buyer_address: buyer.address,
    has_buyer_email: !!(buyer.email && buyer.email.trim().match(/^[^@\s=]+@[^@\s=]+\.[^@\s=]+$/)),
    email_subject: `[공동구매] 주문 접수 – ${buyer.name || '고객'}`,
    email_html:    emailHtml,
    webhook_payload,
  }
}];

