// Normalize Submit Payload (Universal Fix)
// 입력: Webhook Body (Array/Object 모두 호환)
// 출력: Finalize Response 구조 + 시트/이메일용 데이터 완벽 보정

const inputData = $json || {};
// n8n Webhook 구조에 따라 body가 감싸져 있을 수도 있고 아닐 수도 있음
const p = inputData.body || inputData; 

// [유틸] 객체든 배열이든 무조건 배열로 변환하는 함수
const toArray = (data) => {
  if (Array.isArray(data)) return data;
  if (data && typeof data === 'object') return Object.values(data);
  return [];
};

// [유틸] 값 안전하게 찾기
const pick = (obj1, obj2, keys) => {
  for (const k of keys) {
    const v = obj1?.[k] || obj2?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== '') return String(v).trim();
  }
  return '';
};

// 1. Groups 추출 (객체/배열 자동 호환)
const groups = toArray(p.groups);
const firstGroup = groups[0] || {};

// 2. Items 추출 (가장 중요한 부분: 어디에 숨어있든 찾아냄)
let rawItems = [];

// 우선순위 1: groups[0] 안의 items
if (firstGroup.items) {
  rawItems = toArray(firstGroup.items);
}
// 우선순위 2: 최상위(root)의 items (fallback)
if (rawItems.length === 0 && p.items) {
  rawItems = toArray(p.items);
}

// 3. Buyer 정보 추출
const buyer = {
  name:    pick(p, firstGroup, ['buyer_name', 'name', 'customer_name', '이름']),
  crew_name: pick(p, firstGroup, ['crew_name', 'crew']),
  vendor:  pick(p, firstGroup, ['vendor']),
  campaign: pick(p, firstGroup, ['campaign']),
  phone:   pick(p, firstGroup, ['buyer_phone', 'phone', 'tel', 'mobile', '전화번호']),
  email:   pick(p, firstGroup, ['buyer_email', 'email', 'mail', '이메일']),
  address: pick(p, firstGroup, ['buyer_address', 'address', 'addr', '주소']),
  memo:    pick(p, firstGroup, ['buyer_memo', 'memo', 'note', 'notes', '요청사항']),
  marketing_consent: firstGroup.marketing_consent === true || p.marketing_consent === true,
};

// 4. Items 매핑 및 가격 보정
const mapped = rawItems.map((it, idx) => {
  // 숫자 안전 변환
  const original = Number(it.original_price || 0);
  const listed   = Number(it.listed_price || 0);
  const total    = Number(it.total || 0);
  const price    = Number(it.price || 0);
  const qty      = Number(it.qty || it.quantity || 1);

  // 단가 추정 (Total이 있으면 역산, 아니면 listed 사용)
  let unitPrice = price;
  if (unitPrice === 0 && total > 0) unitPrice = Math.round(total / qty);
  if (unitPrice === 0) unitPrice = listed; 
  if (unitPrice === 0 && original > 0) unitPrice = original; // 최후의 수단

  // [핵심] 시트/이메일에 표시할 가격 결정
  // original(소비자가)이 없으면 -> listed(판매가) -> unitPrice 순으로 채움
  const finalOriginalPrice = original > 0 ? original : (listed > 0 ? listed : unitPrice);
  const finalDisplayPrice  = Number(it.display_price) > 0 ? Number(it.display_price) : finalOriginalPrice;

  return {
    item_idx: idx,
    // [중요] 이름이 없으면 URL이라도 넣어서 확인 가능하게 함
    name: it.name || it.product_name || '상품명 확인불가', 
    product_url: it.url || it.product_url || '',
    qty: qty,
    size: it.size || it.option?.size || '',
    notes: it.notes || '',

    display_price: finalDisplayPrice,
    original_price: finalOriginalPrice, 
    listed_price: listed,

    discount_mode: (it.discount_label === '고정' || it.discount_mode === 'fixed') ? 'fixed' : 'percent',
    discount_label: it.discount_label || (it.discount_rate ? it.discount_rate + '%' : '0%'),
    discount_rate: (String(it.discount_label || '').includes('%'))
      ? Number(String(it.discount_label).replace('%','')) 
      : Number(it.discount_rate || 0),

    total: total > 0 ? total : (unitPrice * qty),
    price: unitPrice,

    // ✅ 영산 공급가 데이터 안전하게 추가 및 공급총액 계산
    supply_rate: Number(it.supply_rate || 0),
    supply_price: Number(it.supply_price || 0),
    supply_total: Number(it.supply_price || 0) * qty,
  };
});

// 5. Summary 계산
let s = p.summary || {};
let items_total = Number(s.items_total || p.items_total || 0);
let shipping_total = Number(s.shipping_total || p.shipping_total || 0);
let grand_total = Number(s.grand_total || p.grand_total || 0);

// 만약 summary가 0원이면 items 기반으로 강제 재계산
if (grand_total === 0 && mapped.length > 0) {
  items_total = mapped.reduce((acc, curr) => acc + curr.total, 0);
  shipping_total = Math.ceil(mapped.reduce((acc, curr) => acc + curr.qty, 0) / 3) * 3500;
  grand_total = items_total + shipping_total;
}

const summary = {
  items_total,
  shipping_total,
  grand_total,
  group_count: 1,
};

return [{
  json: {
    ok: true,
    errors: [],
    summary,
    groups: [{
      group_idx: 0,
      ...buyer,
      items: mapped,
    }]
  }
}];
